noncompliant:
void function() {
  int* ptr = malloc(sizeof(int) * 10);
  // ... use ptr
  // Noncompliant - memory not released
}

void process() {
  char* buffer = (char*)calloc(100, sizeof(char));
  if (some_condition) {
    return; // Noncompliant - early return without free
  }
  free(buffer);
}

int* create_array() {
  int* arr = new int[10];
  return arr; // Noncompliant - caller responsibility not clear
}

compliant:
void function() {
  int* ptr = malloc(sizeof(int) * 10);
  if (ptr != NULL) {
    // ... use ptr
    free(ptr); // Compliant - memory properly released
    ptr = NULL;
  }
}

void process() {
  char* buffer = (char*)calloc(100, sizeof(char));
  if (buffer == NULL) return;
  if (some_condition) {
    free(buffer); // Compliant - memory freed before early return
    return;
  }
  free(buffer); // Compliant - memory freed at end
}

// Using RAII pattern
class IntArray {
  int* data;
public:
  IntArray(size_t size) : data(new int[size]) {}
  ~IntArray() { delete[] data; } // Compliant - automatic cleanup
};
